import re

def normalize_nombre(raw):
    if raw is None:
        return None
    return re.sub(r"\s+", " ", str(raw).strip())

print(repr(normalize_nombre("  Ana   María  ")))
print(normalize_nombre(normalize_nombre("  Ana   María  ")))

