from typing import Optional

def maybe_int(raw: str) -> Optional[int]:
    s = raw.strip()
    if not s:
        return None
    return int(s)

print(maybe_int("10"), maybe_int("  "))

def normalize_nombre(raw: str) -> str:
    return " ".join(raw.split())

assert normalize_nombre("  Ana  María ") == "Ana María"
assert normalize_nombre(normalize_nombre("  Ana  María ")) == "Ana María"
print("idempotente ok")

def pure_sum(xs):
    return sum(xs)

def impure_log(xs):
    print("len", len(xs))  # side effect
    return sum(xs)

