def safe_div(a, b):
    if b == 0:
        raise ValueError("b no puede ser 0")
    return a / b

try:
    print(safe_div(10, 2))
    print(safe_div(1, 0))
except ValueError as e:
    print("err", e)

def pipeline(raw: str) -> dict:
    cleaned = " ".join(raw.split())
    return {"raw": raw, "clean": cleaned, "n": len(cleaned)}

print(pipeline("  Ana  "))

def step_strip(s):
    return s.strip()

def step_upper(s):
    return s.upper()

def run(s):
    return step_upper(step_strip(s))

print(run("  hola "))

def validate_nonempty(s: str) -> str:
    t = s.strip()
    if not t:
        raise ValueError("vacío")
    return t

for v in ("  x ", "   "):
    try:
        print(validate_nonempty(v))
    except ValueError as e:
        print("err", e)

