def score_band(s: float) -> str:
    if s >= 0.8:
        return "high"
    if s >= 0.4:
        return "mid"
    return "low"

print(score_band(0.9), score_band(0.5), score_band(0.1))

def normalize_nombre(raw: str) -> str:
    return " ".join(raw.split())

suite = [
    ("  Ana  ", "Ana"),
    ("Ana  María", "Ana María"),
    ("", ""),
]
for inp, exp in suite:
    got = normalize_nombre(inp)
    assert got == exp, (inp, got, exp)
    print(inp, "->", got)
print("suite pass")
